// WebGPU compat test #10 — aether's GQA attention WGSL kernel (KV cache on GPU)
// under monster.
//
// WGSL_ATTENTION copied VERBATIM from
//   open-source/aether/dist-browser/sovereign-shaders.js
// One invocation per query head: numerically-stable softmax (max pass + exp-sum
// pass) over the KV cache, GQA head grouping (numHeads / numKvHeads), weighted V
// sum. Golden-diffed monster vs the Deno real-navigator.gpu oracle.
//
// Inline pure-JS encoders. NB monster gap (learned in test 09): split every
// multi-declarator `const a=..,b=..` into separate statements, else the later
// name binds to a module shim. f32 inputs are small exact values; output
// quantized to 1e-4 to absorb sub-ULP exp/softmax divergence.

function f32bytes(x) {
  if (x === 0) return [0, 0, 0, 0];
  const sign = x < 0 ? 1 : 0; x = Math.abs(x);
  let e = Math.floor(Math.log2(x)); let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; } if (m >= 2) { m /= 2; e += 1; }
  const bits = ((sign << 31) | ((e + 127) << 23) | Math.round((m - 1) * Math.pow(2, 23))) >>> 0;
  return [bits & 0xff, (bits >>> 8) & 0xff, (bits >>> 16) & 0xff, (bits >>> 24) & 0xff];
}
function bytesToF32(b0, b1, b2, b3) {
  const bits = ((b0) | (b1 << 8) | (b2 << 16) | (b3 << 24)) >>> 0;
  const sign = (bits >>> 31) & 1 ? -1 : 1;
  const exp = (bits >>> 23) & 0xff;
  const mant = bits & 0x7fffff;
  if (exp === 0) return sign * mant * Math.pow(2, -149);
  if (exp === 255) return mant ? NaN : sign * Infinity;
  return sign * (1 + mant / Math.pow(2, 23)) * Math.pow(2, exp - 127);
}
function u32bytes(v) { return [v & 0xff, (v >>> 8) & 0xff, (v >>> 16) & 0xff, (v >>> 24) & 0xff]; }
function q4(v) { const s = v < 0 ? -1 : 1; return s * Math.round(Math.abs(v) * 1e4) / 1e4; }

const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();

// GQA: 4 query heads, 2 KV heads (group size 2), headDim 4, seqLen 3.
const NUM_HEADS = 4;
const NUM_KV_HEADS = 2;
const HEAD_DIM = 4;
const SEQ_LEN = 3;
const KV_DIM = NUM_KV_HEADS * HEAD_DIM; // 8
const Q_LEN = NUM_HEADS * HEAD_DIM;     // 16

// Small exact f32 generators (multiples of 0.25 → exact, dot products exact).
function qval(i) { return ((i % 7) - 3) * 0.25; }      // q[i], -0.75..0.75
function kval(i) { return (((i * 3) % 5) - 2) * 0.25; } // kCache[i]
function vval(i) { return (((i * 2) % 9) - 4) * 0.25; } // vCache[i]

let qBytes = [];
for (let i = 0; i < Q_LEN; i++) qBytes = qBytes.concat(f32bytes(qval(i)));
let kBytes = [];
for (let i = 0; i < SEQ_LEN * KV_DIM; i++) kBytes = kBytes.concat(f32bytes(kval(i)));
let vBytes = [];
for (let i = 0; i < SEQ_LEN * KV_DIM; i++) vBytes = vBytes.concat(f32bytes(vval(i)));

// AttnDims { numHeads, numKvHeads, headDim, seqLen, kvDim } (5 x u32)
let dimBytes = [];
dimBytes = dimBytes.concat(u32bytes(NUM_HEADS)).concat(u32bytes(NUM_KV_HEADS))
  .concat(u32bytes(HEAD_DIM)).concat(u32bytes(SEQ_LEN)).concat(u32bytes(KV_DIM));

const Q_BYTES = Q_LEN * 4;
const KV_BYTES = SEQ_LEN * KV_DIM * 4;
const OUT_BYTES = Q_LEN * 4;
const DIM_BYTES = 5 * 4;

const qBuf = device.createBuffer({ size: Q_BYTES, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(qBuf, 0, new Uint8Array(qBytes));
const kBuf = device.createBuffer({ size: KV_BYTES, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(kBuf, 0, new Uint8Array(kBytes));
const vBuf = device.createBuffer({ size: KV_BYTES, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(vBuf, 0, new Uint8Array(vBytes));
const oBuf = device.createBuffer({ size: OUT_BYTES, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_SRC });
const dBuf = device.createBuffer({ size: DIM_BYTES, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(dBuf, 0, new Uint8Array(dimBytes));

const shader = device.createShaderModule({
  code: `
struct AttnDims { numHeads: u32, numKvHeads: u32, headDim: u32, seqLen: u32, kvDim: u32 };
@group(0) @binding(0) var<storage, read> q: array<f32>;
@group(0) @binding(1) var<storage, read> kCache: array<f32>;
@group(0) @binding(2) var<storage, read> vCache: array<f32>;
@group(0) @binding(3) var<storage, read_write> out: array<f32>;
@group(0) @binding(4) var<uniform> d: AttnDims;

@compute @workgroup_size(32, 1, 1)
fn main(@builtin(global_invocation_id) gid: vec3<u32>) {
  let h = gid.x;
  if (h >= d.numHeads) { return; }
  let hpkv = d.numHeads / d.numKvHeads;
  let kvHead = h / hpkv;
  let qOff = h * d.headDim;
  let kvOff = kvHead * d.headDim;
  let scale = 1.0 / sqrt(f32(d.headDim));

  var maxScore: f32 = -3.0e38;
  for (var t: u32 = 0u; t < d.seqLen; t = t + 1u) {
    let kBase = t * d.kvDim + kvOff;
    var s: f32 = 0.0;
    for (var i: u32 = 0u; i < d.headDim; i = i + 1u) {
      s = s + q[qOff + i] * kCache[kBase + i];
    }
    s = s * scale;
    maxScore = max(maxScore, s);
  }
  var denom: f32 = 0.0;
  for (var i: u32 = 0u; i < d.headDim; i = i + 1u) { out[qOff + i] = 0.0; }
  for (var t: u32 = 0u; t < d.seqLen; t = t + 1u) {
    let kBase = t * d.kvDim + kvOff;
    var s: f32 = 0.0;
    for (var i: u32 = 0u; i < d.headDim; i = i + 1u) {
      s = s + q[qOff + i] * kCache[kBase + i];
    }
    let w = exp(min(s * scale - maxScore, 80.0));
    denom = denom + w;
    let vBase = t * d.kvDim + kvOff;
    for (var i: u32 = 0u; i < d.headDim; i = i + 1u) {
      out[qOff + i] = out[qOff + i] + w * vCache[vBase + i];
    }
  }
  let inv = select(1.0 / f32(d.seqLen), 1.0 / denom, denom > 0.0);
  for (var i: u32 = 0u; i < d.headDim; i = i + 1u) {
    out[qOff + i] = out[qOff + i] * inv;
  }
}
`,
});
const pipeline = device.createComputePipeline({ layout: 'auto', compute: { module: shader, entryPoint: 'main' } });
const bindGroup = device.createBindGroup({
  layout: pipeline.getBindGroupLayout(0),
  entries: [
    { binding: 0, resource: { buffer: qBuf } },
    { binding: 1, resource: { buffer: kBuf } },
    { binding: 2, resource: { buffer: vBuf } },
    { binding: 3, resource: { buffer: oBuf } },
    { binding: 4, resource: { buffer: dBuf } },
  ],
});

const enc = device.createCommandEncoder();
const pass = enc.beginComputePass();
pass.setPipeline(pipeline);
pass.setBindGroup(0, bindGroup);
pass.dispatchWorkgroups(1, 1, 1);
pass.end();
const readBuf = device.createBuffer({ size: OUT_BYTES, usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ });
enc.copyBufferToBuffer(oBuf, 0, readBuf, 0, OUT_BYTES);
device.queue.submit([enc.finish()]);

await readBuf.mapAsync(GPUMapMode.READ);
const px = new Uint8Array(readBuf.getMappedRange());
let gpu = [];
for (let i = 0; i < Q_LEN; i++) { const o = i * 4; gpu = gpu.concat([bytesToF32(px[o], px[o + 1], px[o + 2], px[o + 3])]); }
readBuf.unmap();

// Independent CPU reference (mirror the WGSL exactly).
function cpuAttn() {
  let res = [];
  for (let i = 0; i < Q_LEN; i++) res = res.concat([0]);
  const hpkv = NUM_HEADS / NUM_KV_HEADS;
  const scale = 1 / Math.sqrt(HEAD_DIM);
  for (let h = 0; h < NUM_HEADS; h++) {
    const kvHead = Math.floor(h / hpkv);
    const qOff = h * HEAD_DIM;
    const kvOff = kvHead * HEAD_DIM;
    let maxScore = -3.0e38;
    for (let t = 0; t < SEQ_LEN; t++) {
      const kBase = t * KV_DIM + kvOff;
      let s = 0;
      for (let i = 0; i < HEAD_DIM; i++) s += qval(qOff + i) * kval(kBase + i);
      s = s * scale;
      if (s > maxScore) maxScore = s;
    }
    let denom = 0;
    const acc = [];
    for (let i = 0; i < HEAD_DIM; i++) acc.push(0);
    for (let t = 0; t < SEQ_LEN; t++) {
      const kBase = t * KV_DIM + kvOff;
      let s = 0;
      for (let i = 0; i < HEAD_DIM; i++) s += qval(qOff + i) * kval(kBase + i);
      const w = Math.exp(Math.min(s * scale - maxScore, 80));
      denom += w;
      const vBase = t * KV_DIM + kvOff;
      for (let i = 0; i < HEAD_DIM; i++) acc[i] += w * vval(vBase + i);
    }
    const inv = denom > 0 ? 1 / denom : 1 / SEQ_LEN;
    for (let i = 0; i < HEAD_DIM; i++) res[qOff + i] = acc[i] * inv;
  }
  return res;
}
const cpu = cpuAttn();

out.gpu = gpu.map(q4);
out.cpu = cpu.map(q4);
console.error('RAW gpu=' + JSON.stringify(gpu.slice(0, 8)));
console.log('__RESULT__ ' + JSON.stringify(out));
